  ('generalpolice-94737317-moex-00793', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '可燃性物質置於室內燃燒時，可發生閃燃，置於室外燃燒時則否；造成此種差異現象，與下列何 者關聯性較高？', '["兩者火勢大小之差異", "兩者燃燒速率高低之差異", "兩者火焰是否產生熱輻射", "兩者是否產生輻射能回饋效應"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "98ce0a46ea43", "answer_pdf_sha1": "6bc05257a719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00794', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '當非導體之帶電物體，接近接地體時，除帶電物體與接地體之間發生放電外，幾乎同一時間，沿 著非導體表面發生如樹枝狀發光之放電，此現象稱為：', '["火花放電", "條狀放電", "電暈放電", "沿面放電"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "98ce0a46ea43", "answer_pdf_sha1": "6bc05257a719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00795', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '不易累積靜電之導體，係指體積電阻係數（Ω cm）為多少以下之物質？', '["1015", "1013", "1011", "109"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "98ce0a46ea43", "answer_pdf_sha1": "6bc05257a719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00796', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '影響自然發火之因素，下列敘述何者正確？', '["熱傳導度愈大，愈容易傳導熱，愈易起火", "氣體熱傳導度大於液體及固體，故愈易引起燃燒", "同一物質，粉狀蓄熱條件較整塊為佳，故較易起火", "物質含大量水分時，熱傳導度小，故易蓄熱起火"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "98ce0a46ea43", "answer_pdf_sha1": "6bc05257a719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00797', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '有關乙炔及其容器之危險性，下列敘述何者錯誤？', '["乙炔之分解爆炸，壓力越高，最小點火能量越小", "高壓情況下，乙炔易生聚合反應，升溫發熱，促使分解爆炸", "當乙炔噴出時，丙酮粒子亦一併噴出而發生靜電，其電荷可達10,000V以上", "界限壓力隨容器管徑增加而上升"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "98ce0a46ea43", "answer_pdf_sha1": "6bc05257a719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00798', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '有關家用天然氣事故之處置方式，下列敘述何者錯誤？', '["關閉天然氣開關", "熄滅附近火源", "迅速打開門窗，使室內空氣流通", "立即關閉電氣開關並拔除電源"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "98ce0a46ea43", "answer_pdf_sha1": "6bc05257a719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
