  ('generalpolice-94737317-moex-00800', 'generalpolice-94737317', 'generalpolice-94737317-moex-110-5f3f518e', 'sub-generalpolice-94737317-04', NULL, 'single_choice', '爆炸對於消防救災產生潛在之危害，下列敘述何者正確？', '["依能量大小分為爆燃及爆轟", "火焰面和衝擊波發展成同一波，稱為爆轟", "氣體燃燒形成之爆炸主要是指擴散燃燒", "爆燃對於人體及周遭物體造成之影響大於爆轟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:49+00:00", "source_pdf_sha1": "98ce0a46ea43", "answer_pdf_sha1": "6bc05257a719", "source_family": "moex-gov-tw", "moex": {"exam_code": "110070", "c": "402", "s": "1307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "火災學概要", "year": "110", "exam_name": "110年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
